    72→            onPressIconRight={rightIconOnPress}
    73→            titleColor={titleColor as PropsHeader['titleColor']}
    74→            iconColorLeft={leftIconColor as PropsHeader['iconColorLeft']}
    75→            iconColorOnOption={rightIconColor as PropsHeader['iconColorOnOption']}
    76→            testID="icon-home-button"
    77→          />
    78→        ) : null}
    79→        {headerTitle ? (
    80→          <Box
    81→            width="100%"
