    96→                  color="BRAND_COMPLEMENT_02"
    97→                />
    98→              )}
    99→              <Icon
   100→                name={rightIcon}
   101→                color="BRAND_COMPLEMENT_02"
   102→                onPress={rightIconOnPress}
   103→              />
   104→            </Box>
   105→          </Box>
   106→        ) : null}
   107→        {hasScroll ? (
   108→          <ScrollView
   109→            ref={scrollViewRef}
   110→            {...scrollViewProps}
   111→            scrollEnabled={hasScroll}
   112→            scrollEventThrottle={throttle ?? 0}
